const WebSocket = require('ws');

const PORT = process.env.PORT || 8080;
const TICK_RATE = 20;
const MAP_WIDTH = 2000;
const MAP_HEIGHT = 2000;
const UNIT_SPEED = 80;
const ATTACK_RANGE = 70;
const ATTACK_DAMAGE = 10;
const ATTACK_COOLDOWN_MS = 700;
const BUILD_TIME_MS = 3000;
const RESOURCE_START = 1000;

const wss = new WebSocket.Server({ port: PORT });

let nextPlayerId = 1;
let nextEntityId = 1;
const players = new Map();
const sockets = new Map();
const game = {
  entities: new Map(),
  lastTick: Date.now()
};

function now() {
  return Date.now();
}

function clamp(v, min, max) {
  return Math.max(min, Math.min(max, v));
}

function distance(a, b) {
  const dx = a.x - b.x;
  const dy = a.y - b.y;
  return Math.sqrt(dx * dx + dy * dy);
}

function generateId() {
  return nextEntityId++;
}

function createPlayer(ws) {
  const id = nextPlayerId++;
  const spawnX = 100 + ((id * 173) % (MAP_WIDTH - 200));
  const spawnY = 100 + ((id * 257) % (MAP_HEIGHT - 200));

  const base = {
    id: generateId(),
    type: 'building',
    ownerId: id,
    subtype: 'hq',
    x: spawnX,
    y: spawnY,
    hp: 500,
    maxHp: 500,
    radius: 28,
    buildProgress: 1,
    completed: true
  };

  const worker = {
    id: generateId(),
    type: 'unit',
    ownerId: id,
    subtype: 'worker',
    x: spawnX + 40,
    y: spawnY + 20,
    hp: 50,
    maxHp: 50,
    radius: 10,
    speed: UNIT_SPEED,
    targetPos: null,
    attackTargetId: null,
    lastAttackAt: 0
  };

  game.entities.set(base.id, base);
  game.entities.set(worker.id, worker);

  const player = {
    id,
    resources: RESOURCE_START,
    selected: [],
    baseId: base.id
  };

  players.set(id, player);
  sockets.set(ws, id);
  return player;
}

function removePlayer(ws) {
  const playerId = sockets.get(ws);
  if (!playerId) return;
  sockets.delete(ws);
  players.delete(playerId);

  for (const [id, entity] of game.entities) {
    if (entity.ownerId === playerId) {
      game.entities.delete(id);
    }
  }

  broadcast({
    type: 'player_left',
    playerId
  });
}

function serializeEntity(entity) {
  return {
    id: entity.id,
    type: entity.type,
    subtype: entity.subtype,
    ownerId: entity.ownerId,
    x: entity.x,
    y: entity.y,
    hp: entity.hp,
    maxHp: entity.maxHp,
    radius: entity.radius,
    buildProgress: entity.buildProgress ?? 1,
    completed: entity.completed ?? true,
    targetPos: entity.targetPos,
    attackTargetId: entity.attackTargetId ?? null
  };
}

function getFullStateFor(playerId) {
  return {
    type: 'state',
    playerId,
    map: {
      width: MAP_WIDTH,
      height: MAP_HEIGHT
    },
    resources: players.get(playerId)?.resources ?? 0,
    entities: Array.from(game.entities.values()).map(serializeEntity),
    serverTime: now()
  };
}

function send(ws, message) {
  if (ws.readyState === WebSocket.OPEN) {
    ws.send(JSON.stringify(message));
  }
}

function broadcast(message) {
  const data = JSON.stringify(message);
  for (const client of wss.clients) {
    if (client.readyState === WebSocket.OPEN) {
      client.send(data);
    }
  }
}

function broadcastState() {
  const entities = Array.from(game.entities.values()).map(serializeEntity);
  for (const client of wss.clients) {
    if (client.readyState !== WebSocket.OPEN) continue;
    const playerId = sockets.get(client);
    client.send(JSON.stringify({
      type: 'state',
      playerId,
      map: {
        width: MAP_WIDTH,
        height: MAP_HEIGHT
      },
      resources: players.get(playerId)?.resources ?? 0,
      entities,
      serverTime: now()
    }));
  }
}

function createBuilding(playerId, subtype, x, y) {
  let cost = 200;
  let hp = 200;
  let radius = 20;

  if (subtype === 'barracks') {
    cost = 300;
    hp = 300;
    radius = 24;
  } else if (subtype === 'turret') {
    cost = 250;
    hp = 180;
    radius = 18;
  } else if (subtype === 'supply') {
    cost = 150;
    hp = 150;
    radius = 16;
  }

  const player = players.get(playerId);
  if (!player || player.resources < cost) return null;

  player.resources -= cost;

  const entity = {
    id: generateId(),
    type: 'building',
    ownerId: playerId,
    subtype,
    x: clamp(x, 0, MAP_WIDTH),
    y: clamp(y, 0, MAP_HEIGHT),
    hp: hp,
    maxHp: hp,
    radius,
    buildProgress: 0,
    completed: false,
    buildCompleteAt: now() + BUILD_TIME_MS
  };

  game.entities.set(entity.id, entity);
  return entity;
}

function createUnit(playerId, subtype, x, y) {
  let hp = 60;
  let speed = UNIT_SPEED;
  let radius = 10;

  if (subtype === 'soldier') {
    hp = 100;
    speed = 75;
    radius = 11;
  } else if (subtype === 'tank') {
    hp = 250;
    speed = 45;
    radius = 16;
  }

  const entity = {
    id: generateId(),
    type: 'unit',
    ownerId: playerId,
    subtype,
    x: clamp(x, 0, MAP_WIDTH),
    y: clamp(y, 0, MAP_HEIGHT),
    hp,
    maxHp: hp,
    radius,
    speed,
    targetPos: null,
    attackTargetId: null,
    lastAttackAt: 0
  };

  game.entities.set(entity.id, entity);
  return entity;
}

function handleBuildCommand(playerId, msg) {
  const { subtype, x, y, sourceBuildingId } = msg;
  if (typeof subtype !== 'string') return;

  if (subtype === 'worker' || subtype === 'soldier' || subtype === 'tank') {
    const source = game.entities.get(sourceBuildingId);
    if (!source || source.ownerId !== playerId || source.type !== 'building' || !source.completed) return;

    const player = players.get(playerId);
    if (!player) return;

    let cost = 100;
    if (subtype === 'soldier') cost = 120;
    if (subtype === 'tank') cost = 300;

    if (player.resources < cost) return;
    player.resources -= cost;

    const spawnX = source.x + source.radius + 20;
    const spawnY = source.y + source.radius + 20;
    createUnit(playerId, subtype, spawnX, spawnY);
    return;
  }

  if (typeof x !== 'number' || typeof y !== 'number') return;
  createBuilding(playerId, subtype, x, y);
}

function handleMoveCommand(playerId, msg) {
  const { unitIds, x, y } = msg;
  if (!Array.isArray(unitIds) || typeof x !== 'number' || typeof y !== 'number') return;

  const tx = clamp(x, 0, MAP_WIDTH);
  const ty = clamp(y, 0, MAP_HEIGHT);

  unitIds.forEach((unitId, index) => {
    const entity = game.entities.get(unitId);
    if (!entity || entity.ownerId !== playerId || entity.type !== 'unit') return;
    const offsetX = (index % 5) * 16;
    const offsetY = Math.floor(index / 5) * 16;
    entity.targetPos = {
      x: clamp(tx + offsetX, 0, MAP_WIDTH),
      y: clamp(ty + offsetY, 0, MAP_HEIGHT)
    };
    entity.attackTargetId = null;
  });
}

function handleAttackCommand(playerId, msg) {
  const { unitIds, targetId } = msg;
  if (!Array.isArray(unitIds) || typeof targetId !== 'number') return;

  const target = game.entities.get(targetId);
  if (!target) return;

  unitIds.forEach((unitId) => {
    const entity = game.entities.get(unitId);
    if (!entity || entity.ownerId !== playerId || entity.type !== 'unit') return;
    entity.attackTargetId = targetId;
    entity.targetPos = null;
  });
}

function handleMessage(ws, raw) {
  let msg;
  try {
    msg = JSON.parse(raw.toString());
  } catch {
    send(ws, { type: 'error', message: 'Invalid JSON' });
    return;
  }

  const playerId = sockets.get(ws);
  if (!playerId) return;

  if (!msg || typeof msg.type !== 'string') {
    send(ws, { type: 'error', message: 'Invalid message' });
    return;
  }

  if (msg.type === 'build') {
    handleBuildCommand(playerId, msg);
  } else if (msg.type === 'move') {
    handleMoveCommand(playerId, msg);
  } else if (msg.type === 'attack') {
    handleAttackCommand(playerId, msg);
  } else if (msg.type === 'ping') {
    send(ws, { type: 'pong', serverTime: now() });
  } else {
    send(ws, { type: 'error', message: 'Unknown command type' });
  }
}

function updateBuildingProgress(currentTime) {
  for (const entity of game.entities.values()) {
    if (entity.type === 'building' && !entity.completed) {
      const remaining = entity.buildCompleteAt - currentTime;
      if (remaining <= 0) {
        entity.completed = true;
        entity.buildProgress = 1;
        delete entity.buildCompleteAt;
      } else {
        entity.buildProgress = 1 - (remaining / BUILD_TIME_MS);
      }
    }
  }
}

function moveUnit(unit, dt) {
  if (!unit.targetPos) return;

  const dx = unit.targetPos.x - unit.x;
  const dy = unit.targetPos.y - unit.y;
  const dist = Math.sqrt(dx * dx + dy * dy);

  if (dist <= 1) {
    unit.x = unit.targetPos.x;
    unit.y = unit.targetPos.y;
    unit.targetPos = null;
    return;
  }

  const maxStep = unit.speed * dt;
  if (dist <= maxStep) {
    unit.x = unit.targetPos.x;
    unit.y = unit.targetPos.y;
    unit.targetPos = null;
  } else {
    unit.x += (dx / dist) * maxStep;
    unit.y += (dy / dist) * maxStep;
  }

  unit.x = clamp(unit.x, 0, MAP_WIDTH);
  unit.y = clamp(unit.y, 0, MAP_HEIGHT);
}

function processCombat(currentTime) {
  const toDelete = [];

  for (const entity of game.entities.values()) {
    if (entity.type !== 'unit') continue;
    if (!entity.attackTargetId) continue;

    const target = game.entities.get(entity.attackTargetId);
    if (!target || target.ownerId === entity.ownerId) {
      entity.attackTargetId = null;
      continue;
    }

    const dist = distance(entity, target);
    const desired = ATTACK_RANGE + entity.radius + target.radius;

    if (dist > desired) {
      entity.targetPos = { x: target.x, y: target.y };
      moveUnit(entity, 1 / TICK_RATE);
      continue;
    }

    entity.targetPos = null;

    if (currentTime - entity.lastAttackAt >= ATTACK_COOLDOWN_MS) {
      entity.lastAttackAt = currentTime;
      target.hp -= ATTACK_DAMAGE;

      if (target.hp <= 0) {
        toDelete.push(target.id);
        entity.attackTargetId = null;

        const owner = players.get(entity.ownerId);
        if (owner) owner.resources += 25;
      }
    }
  }

  for (const id of toDelete) {
    game.entities.delete(id);
    for (const entity of game.entities.values()) {
      if (entity.attackTargetId === id) {
        entity.attackTargetId = null;
      }
    }
  }
}

function updateUnits(dt) {
  for (const entity of game.entities.values()) {
    if (entity.type !== 'unit') continue;
    if (entity.attackTargetId) continue;
    moveUnit(entity, dt);
  }
}

function gameLoop() {
  const currentTime = now();
  const dt = Math.min(0.25, (currentTime - game.lastTick) / 1000);
  game.lastTick = currentTime;

  updateBuildingProgress(currentTime);
  updateUnits(dt);
  processCombat(currentTime);
  broadcastState();
}

wss.on('connection', (ws) => {
  const player = createPlayer(ws);

  send(ws, {
    type: 'welcome',
    playerId: player.id,
    map: {
      width: MAP_WIDTH,
      height: MAP_HEIGHT
    },
    resources: player.resources
  });

  send(ws, getFullStateFor(player.id));

  broadcast({
    type: 'player_joined',
    playerId: player.id
  });

  ws.on('message', (data) => {
    handleMessage(ws, data);
  });

  ws.on('close', () => {
    removePlayer(ws);
  });

  ws.on('error', () => {
    removePlayer(ws);
  });
});

setInterval(gameLoop, 1000 / TICK_RATE);

console.log(`RTS WebSocket server running on ws://localhost:${PORT}`);